import{_ as a,o,c as s,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Doctor","description":"","frontmatter":{"read_when":["添加或修改 doctor 迁移","引入破坏性配置更改"],"summary":"Doctor 命令：健康检查、配置迁移和修复步骤","title":"Doctor","x-i18n":{"generated_at":"2026-02-03T07:49:03Z","model":"claude-opus-4-5","provider":"pi","source_hash":"df7b25f60fd08d508f4c6abfc8e7e06f29bd4bbb34c3320397f47eb72c8de83f","source_path":"gateway/doctor.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/doctor.md","filePath":"zh-CN/gateway/doctor.md","lastUpdated":null}'),d={name:"zh-CN/gateway/doctor.md"};function t(l,e,n,c,r,p){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="doctor" tabindex="-1"><a class="header-anchor" href="#doctor">#</a> Doctor</h1><p><code>opensoul doctor</code> 是 OpenSoul 的修复 + 迁移工具。它修复过时的配置/状态，检查健康状况，并提供可操作的修复步骤。</p><h2 id="快速开始" tabindex="-1"><a class="header-anchor" href="#快速开始">#</a> 快速开始</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="无头-自动化" tabindex="-1"><a class="header-anchor" href="#无头-自动化">#</a> 无头/自动化</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --yes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>无需提示接受默认值（包括适用时的重启/服务/沙箱修复步骤）。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --repair</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>无需提示应用推荐的修复（安全时进行修复 + 重启）。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --repair</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也应用激进的修复（覆盖自定义 supervisor 配置）。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --non-interactive</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>无需提示运行，仅应用安全迁移（配置规范化 + 磁盘状态移动）。跳过需要人工确认的重启/服务/沙箱操作。 检测到时自动运行遗留状态迁移。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --deep</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>扫描系统服务以查找额外的 Gateway 网关安装（launchd/systemd/schtasks）。</p><p>如果你想在写入前查看更改，请先打开配置文件：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opensoul/opensoul.json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="功能概述" tabindex="-1"><a class="header-anchor" href="#功能概述">#</a> 功能概述</h2><ul><li>git 安装的可选预检更新（仅交互模式）。</li><li>UI 协议新鲜度检查（当协议 schema 较新时重建 Control UI）。</li><li>健康检查 + 重启提示。</li><li>Skills 状态摘要（符合条件/缺失/被阻止）。</li><li>遗留值的配置规范化。</li><li>OpenCode Zen 提供商覆盖警告（<code>models.providers.opencode</code>）。</li><li>遗留磁盘状态迁移（会话/智能体目录/WhatsApp 认证）。</li><li>状态完整性和权限检查（会话、记录、状态目录）。</li><li>本地运行时的配置文件权限检查（chmod 600）。</li><li>模型认证健康：检查 OAuth 过期，可刷新即将过期的 token，并报告认证配置文件冷却/禁用状态。</li><li>额外工作区目录检测（<code>~/opensoul</code>）。</li><li>启用沙箱隔离时的沙箱镜像修复。</li><li>遗留服务迁移和额外 Gateway 网关检测。</li><li>Gateway 网关运行时检查（服务已安装但未运行；缓存的 launchd 标签）。</li><li>渠道状态警告（从运行中的 Gateway 网关探测）。</li><li>Supervisor 配置审计（launchd/systemd/schtasks）及可选修复。</li><li>Gateway 网关运行时最佳实践检查（Node vs Bun，版本管理器路径）。</li><li>Gateway 网关端口冲突诊断（默认 <code>18789</code>）。</li><li>开放私信策略的安全警告。</li><li>未设置 <code>gateway.auth.token</code> 时的 Gateway 网关认证警告（本地模式；提供 token 生成）。</li><li>Linux 上的 systemd linger 检查。</li><li>源码安装检查（pnpm workspace 不匹配、缺失 UI 资产、缺失 tsx 二进制文件）。</li><li>写入更新后的配置 + 向导元数据。</li></ul><h2 id="详细行为和原理" tabindex="-1"><a class="header-anchor" href="#详细行为和原理">#</a> 详细行为和原理</h2><h3 id="_0-可选更新-git-安装" tabindex="-1"><a class="header-anchor" href="#_0-可选更新-git-安装">#</a> 0）可选更新（git 安装）</h3><p>如果这是 git 检出且 doctor 以交互模式运行，它会在运行 doctor 之前提供更新（fetch/rebase/build）。</p><h3 id="_1-配置规范化" tabindex="-1"><a class="header-anchor" href="#_1-配置规范化">#</a> 1）配置规范化</h3><p>如果配置包含遗留值形式（例如没有渠道特定覆盖的 <code>messages.ackReaction</code>），doctor 会将它们规范化为当前 schema。</p><h3 id="_2-遗留配置键迁移" tabindex="-1"><a class="header-anchor" href="#_2-遗留配置键迁移">#</a> 2）遗留配置键迁移</h3><p>当配置包含已弃用的键时，其他命令会拒绝运行并要求你运行 <code>opensoul doctor</code>。</p><p>Doctor 将：</p><ul><li>解释找到了哪些遗留键。</li><li>显示它应用的迁移。</li><li>使用更新后的 schema 重写 <code>~/.opensoul/opensoul.json</code>。</li></ul><p>Gateway 网关在检测到遗留配置格式时也会在启动时自动运行 doctor 迁移，因此过时的配置无需手动干预即可修复。</p><p>当前迁移：</p><ul><li><code>routing.allowFrom</code> → <code>channels.whatsapp.allowFrom</code></li><li><code>routing.groupChat.requireMention</code> → <code>channels.whatsapp/telegram/imessage.groups.&quot;*&quot;.requireMention</code></li><li><code>routing.groupChat.historyLimit</code> → <code>messages.groupChat.historyLimit</code></li><li><code>routing.groupChat.mentionPatterns</code> → <code>messages.groupChat.mentionPatterns</code></li><li><code>routing.queue</code> → <code>messages.queue</code></li><li><code>routing.bindings</code> → 顶级 <code>bindings</code></li><li><code>routing.agents</code>/<code>routing.defaultAgentId</code> → <code>agents.list</code> + <code>agents.list[].default</code></li><li><code>routing.agentToAgent</code> → <code>tools.agentToAgent</code></li><li><code>routing.transcribeAudio</code> → <code>tools.media.audio.models</code></li><li><code>bindings[].match.accountID</code> → <code>bindings[].match.accountId</code></li><li><code>identity</code> → <code>agents.list[].identity</code></li><li><code>agent.*</code> → <code>agents.defaults</code> + <code>tools.*</code>（tools/elevated/exec/sandbox/subagents）</li><li><code>agent.model</code>/<code>allowedModels</code>/<code>modelAliases</code>/<code>modelFallbacks</code>/<code>imageModelFallbacks</code> → <code>agents.defaults.models</code> + <code>agents.defaults.model.primary/fallbacks</code> + <code>agents.defaults.imageModel.primary/fallbacks</code></li></ul><h3 id="_2b-opencode-zen-提供商覆盖" tabindex="-1"><a class="header-anchor" href="#_2b-opencode-zen-提供商覆盖">#</a> 2b）OpenCode Zen 提供商覆盖</h3><p>如果你手动添加了 <code>models.providers.opencode</code>（或 <code>opencode-zen</code>），它会覆盖 <code>@mariozechner/pi-ai</code> 中内置的 OpenCode Zen 目录。这可能会强制将每个模型放到单个 API 上或将成本归零。Doctor 会发出警告，以便你可以移除覆盖并恢复每模型 API 路由 + 成本。</p><h3 id="_3-遗留状态迁移-磁盘布局" tabindex="-1"><a class="header-anchor" href="#_3-遗留状态迁移-磁盘布局">#</a> 3）遗留状态迁移（磁盘布局）</h3><p>Doctor 可以将旧的磁盘布局迁移到当前结构：</p><ul><li>会话存储 + 记录： <ul><li>从 <code>~/.opensoul/sessions/</code> 到 <code>~/.opensoul/agents/&lt;agentId&gt;/sessions/</code></li></ul></li><li>智能体目录： <ul><li>从 <code>~/.opensoul/agent/</code> 到 <code>~/.opensoul/agents/&lt;agentId&gt;/agent/</code></li></ul></li><li>WhatsApp 认证状态（Baileys）： <ul><li>从遗留的 <code>~/.opensoul/credentials/*.json</code>（除 <code>oauth.json</code> 外）</li><li>到 <code>~/.opensoul/credentials/whatsapp/&lt;accountId&gt;/...</code>（默认账户 id：<code>default</code>）</li></ul></li></ul><p>这些迁移是尽力而为且幂等的；当 doctor 将任何遗留文件夹作为备份保留时会发出警告。Gateway 网关/CLI 也会在启动时自动迁移遗留会话 + 智能体目录，因此历史/认证/模型会落在每智能体路径中，无需手动运行 doctor。WhatsApp 认证有意仅通过 <code>opensoul doctor</code> 迁移。</p><h3 id="_4-状态完整性检查-会话持久化、路由和安全" tabindex="-1"><a class="header-anchor" href="#_4-状态完整性检查-会话持久化、路由和安全">#</a> 4）状态完整性检查（会话持久化、路由和安全）</h3><p>状态目录是操作的核心。如果它消失，你会丢失会话、凭证、日志和配置（除非你在别处有备份）。</p><p>Doctor 检查：</p><ul><li><strong>状态目录缺失</strong>：警告灾难性状态丢失，提示重新创建目录，并提醒你它无法恢复丢失的数据。</li><li><strong>状态目录权限</strong>：验证可写性；提供修复权限（并在检测到所有者/组不匹配时发出 <code>chown</code> 提示）。</li><li><strong>会话目录缺失</strong>：<code>sessions/</code> 和会话存储目录是持久化历史和避免 <code>ENOENT</code> 崩溃所必需的。</li><li><strong>记录不匹配</strong>：当最近的会话条目缺少记录文件时发出警告。</li><li><strong>主会话&quot;1 行 JSONL&quot;</strong>：当主记录只有一行时标记（历史未累积）。</li><li><strong>多个状态目录</strong>：当多个 <code>~/.opensoul</code> 文件夹存在于不同 home 目录或当 <code>OPENSOUL_STATE_DIR</code> 指向别处时发出警告（历史可能在安装之间分裂）。</li><li><strong>远程模式提醒</strong>：如果 <code>gateway.mode=remote</code>，doctor 会提醒你在远程主机上运行它（状态在那里）。</li><li><strong>配置文件权限</strong>：当 <code>~/.opensoul/opensoul.json</code> 对组/其他用户可读时发出警告，并提供收紧到 <code>600</code> 的选项。</li></ul><h3 id="_5-模型认证健康-oauth-过期" tabindex="-1"><a class="header-anchor" href="#_5-模型认证健康-oauth-过期">#</a> 5）模型认证健康（OAuth 过期）</h3><p>Doctor 检查认证存储中的 OAuth 配置文件，在 token 即将过期/已过期时发出警告，并在安全时刷新它们。如果 Anthropic Claude Code 配置文件过时，它会建议运行 <code>claude setup-token</code>（或粘贴 setup-token）。 刷新提示仅在交互运行（TTY）时出现；<code>--non-interactive</code> 跳过刷新尝试。</p><p>Doctor 还会报告由于以下原因暂时不可用的认证配置文件：</p><ul><li>短冷却（速率限制/超时/认证失败）</li><li>长禁用（账单/信用失败）</li></ul><h3 id="_6-hooks-模型验证" tabindex="-1"><a class="header-anchor" href="#_6-hooks-模型验证">#</a> 6）Hooks 模型验证</h3><p>如果设置了 <code>hooks.gmail.model</code>，doctor 会根据目录和允许列表验证模型引用，并在无法解析或不允许时发出警告。</p><h3 id="_7-沙箱镜像修复" tabindex="-1"><a class="header-anchor" href="#_7-沙箱镜像修复">#</a> 7）沙箱镜像修复</h3><p>当启用沙箱隔离时，doctor 检查 Docker 镜像，并在当前镜像缺失时提供构建或切换到遗留名称的选项。</p><h3 id="_8-gateway-网关服务迁移和清理提示" tabindex="-1"><a class="header-anchor" href="#_8-gateway-网关服务迁移和清理提示">#</a> 8）Gateway 网关服务迁移和清理提示</h3><p>Doctor 检测遗留的 Gateway 网关服务（launchd/systemd/schtasks），并提供删除它们并使用当前 Gateway 网关端口安装 OpenSoul 服务的选项。它还可以扫描额外的类 Gateway 网关服务并打印清理提示。 配置文件命名的 OpenSoul Gateway 网关服务被视为一等公民，不会被标记为&quot;额外的&quot;。</p><h3 id="_9-安全警告" tabindex="-1"><a class="header-anchor" href="#_9-安全警告">#</a> 9）安全警告</h3><p>当提供商对私信开放而没有允许列表，或当策略以危险方式配置时，Doctor 会发出警告。</p><h3 id="_10-systemd-linger-linux" tabindex="-1"><a class="header-anchor" href="#_10-systemd-linger-linux">#</a> 10）systemd linger（Linux）</h3><p>如果作为 systemd 用户服务运行，doctor 确保启用 lingering，以便 Gateway 网关在注销后保持活动。</p><h3 id="_11-skills-状态" tabindex="-1"><a class="header-anchor" href="#_11-skills-状态">#</a> 11）Skills 状态</h3><p>Doctor 打印当前工作区符合条件/缺失/被阻止的 Skills 的快速摘要。</p><h3 id="_12-gateway-网关认证检查-本地-token" tabindex="-1"><a class="header-anchor" href="#_12-gateway-网关认证检查-本地-token">#</a> 12）Gateway 网关认证检查（本地 token）</h3><p>当本地 Gateway 网关缺少 <code>gateway.auth</code> 时，Doctor 会发出警告并提供生成 token 的选项。使用 <code>opensoul doctor --generate-gateway-token</code> 在自动化中强制创建 token。</p><h3 id="_13-gateway-网关健康检查-重启" tabindex="-1"><a class="header-anchor" href="#_13-gateway-网关健康检查-重启">#</a> 13）Gateway 网关健康检查 + 重启</h3><p>Doctor 运行健康检查，并在 Gateway 网关看起来不健康时提供重启选项。</p><h3 id="_14-渠道状态警告" tabindex="-1"><a class="header-anchor" href="#_14-渠道状态警告">#</a> 14）渠道状态警告</h3><p>如果 Gateway 网关健康，doctor 运行渠道状态探测并报告警告及建议的修复。</p><h3 id="_15-supervisor-配置审计-修复" tabindex="-1"><a class="header-anchor" href="#_15-supervisor-配置审计-修复">#</a> 15）Supervisor 配置审计 + 修复</h3><p>Doctor 检查已安装的 supervisor 配置（launchd/systemd/schtasks）是否有缺失或过时的默认值（例如 systemd network-online 依赖和重启延迟）。当发现不匹配时，它会推荐更新，并可以将服务文件/任务重写为当前默认值。</p><p>注意事项：</p><ul><li><code>opensoul doctor</code> 在重写 supervisor 配置前提示。</li><li><code>opensoul doctor --yes</code> 接受默认修复提示。</li><li><code>opensoul doctor --repair</code> 无需提示应用推荐的修复。</li><li><code>opensoul doctor --repair --force</code> 覆盖自定义 supervisor 配置。</li><li>你始终可以通过 <code>opensoul gateway install --force</code> 强制完全重写。</li></ul><h3 id="_16-gateway-网关运行时-端口诊断" tabindex="-1"><a class="header-anchor" href="#_16-gateway-网关运行时-端口诊断">#</a> 16）Gateway 网关运行时 + 端口诊断</h3><p>Doctor 检查服务运行时（PID、上次退出状态），并在服务已安装但实际未运行时发出警告。它还检查 Gateway 网关端口（默认 <code>18789</code>）上的端口冲突，并报告可能的原因（Gateway 网关已在运行、SSH 隧道）。</p><h3 id="_17-gateway-网关运行时最佳实践" tabindex="-1"><a class="header-anchor" href="#_17-gateway-网关运行时最佳实践">#</a> 17）Gateway 网关运行时最佳实践</h3><p>当 Gateway 网关服务在 Bun 或版本管理器管理的 Node 路径（<code>nvm</code>、<code>fnm</code>、<code>volta</code>、<code>asdf</code> 等）上运行时，Doctor 会发出警告。WhatsApp + Telegram 渠道需要 Node，版本管理器路径在升级后可能会中断，因为服务不会加载你的 shell init。Doctor 会在可用时提供迁移到系统 Node 安装的选项（Homebrew/apt/choco）。</p><h3 id="_18-配置写入-向导元数据" tabindex="-1"><a class="header-anchor" href="#_18-配置写入-向导元数据">#</a> 18）配置写入 + 向导元数据</h3><p>Doctor 持久化任何配置更改，并标记向导元数据以记录 doctor 运行。</p><h3 id="_19-工作区提示-备份-记忆系统" tabindex="-1"><a class="header-anchor" href="#_19-工作区提示-备份-记忆系统">#</a> 19）工作区提示（备份 + 记忆系统）</h3><p>当缺失时，Doctor 建议使用工作区记忆系统，并在工作区尚未在 git 下时打印备份提示。</p><p>参见 <a href="/docs/concepts/agent-workspace">/concepts/agent-workspace</a> 了解工作区结构和 git 备份的完整指南（推荐私有 GitHub 或 GitLab）。</p>',76)])])}const g=a(d,[["render",t]]);export{u as __pageData,g as default};
